package main

import (
	"encoding/json"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/gorilla/websocket"
)

type Role string

const (
	RolePlayer Role = "player"
	RoleMod    Role = "mod"
	RoleAdmin  Role = "admin"
)

type ClientMessage struct {
	Type    string `json:"type"`
	Message string `json:"message"`
}

type ServerMessage struct {
	Type    string      `json:"type"`
	Payload interface{} `json:"payload"`
}

type Client struct {
	ID       string
	Name     string
	Role     Role
	Conn     *websocket.Conn
	Send     chan []byte
	Server   *Server
	LastSeen time.Time
}

type Server struct {
	mu       sync.RWMutex
	clients  map[string]*Client
	banned   map[string]bool
	upgrader websocket.Upgrader
}

func NewServer() *Server {
	return &Server{
		clients: make(map[string]*Client),
		banned:  make(map[string]bool),
		upgrader: websocket.Upgrader{
			CheckOrigin: func(r *http.Request) bool { return true },
		},
	}
}

func (s *Server) HandleWS(w http.ResponseWriter, r *http.Request) {
	id := strings.TrimSpace(r.Header.Get("X-User-ID"))
	name := strings.TrimSpace(r.Header.Get("X-User-Name"))
	role := Role(strings.ToLower(strings.TrimSpace(r.Header.Get("X-User-Role"))))

	if id == "" {
		http.Error(w, "missing user id", http.StatusBadRequest)
		return
	}
	if name == "" {
		name = id
	}
	if role == "" {
		role = RolePlayer
	}

	s.mu.RLock()
	if s.banned[id] {
		s.mu.RUnlock()
		http.Error(w, "banned", http.StatusForbidden)
		return
	}
	s.mu.RUnlock()

	conn, err := s.upgrader.Upgrade(w, r, nil)
	if err != nil {
		return
	}

	client := &Client{
		ID:       id,
		Name:     name,
		Role:     role,
		Conn:     conn,
		Send:     make(chan []byte, 64),
		Server:   s,
		LastSeen: time.Now(),
	}

	s.addClient(client)
	go client.writeLoop()
	client.readLoop()
}

func (s *Server) addClient(c *Client) {
	s.mu.Lock()
	if existing, ok := s.clients[c.ID]; ok {
		close(existing.Send)
		_ = existing.Conn.Close()
	}
	s.clients[c.ID] = c
	s.mu.Unlock()

	s.broadcastSystem(c.Name + " joined the game")
}

func (s *Server) removeClient(c *Client) {
	s.mu.Lock()
	if current, ok := s.clients[c.ID]; ok && current == c {
		delete(s.clients, c.ID)
	}
	s.mu.Unlock()

	s.broadcastSystem(c.Name + " left the game")
}

func (s *Server) broadcastSystem(msg string) {
	s.broadcast(ServerMessage{
		Type: "system",
		Payload: map[string]string{
			"message": msg,
		},
	})
}

func (s *Server) broadcastChat(from, msg string) {
	s.broadcast(ServerMessage{
		Type: "chat",
		Payload: map[string]string{
			"from":    from,
			"message": msg,
		},
	})
}

func (s *Server) broadcast(v ServerMessage) {
	data, err := json.Marshal(v)
	if err != nil {
		return
	}

	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, c := range s.clients {
		select {
		case c.Send <- data:
		default:
		}
	}
}

func (s *Server) sendTo(client *Client, v ServerMessage) {
	data, err := json.Marshal(v)
	if err != nil {
		return
	}
	select {
	case client.Send <- data:
	default:
	}
}

func (c *Client) readLoop() {
	defer func() {
		c.Server.removeClient(c)
		_ = c.Conn.Close()
	}()

	for {
		var msg ClientMessage
		if err := c.Conn.ReadJSON(&msg); err != nil {
			return
		}
		c.LastSeen = time.Now()

		switch msg.Type {
		case "chat":
			c.handleChat(msg.Message)
		default:
			c.Server.sendTo(c, ServerMessage{
				Type: "error",
				Payload: map[string]string{
					"message": "unknown message type",
				},
			})
		}
	}
}

func (c *Client) writeLoop() {
	defer func() {
		_ = c.Conn.Close()
	}()
	for msg := range c.Send {
		if err := c.Conn.WriteMessage(websocket.TextMessage, msg); err != nil {
			return
		}
	}
}

func (c *Client) handleChat(message string) {
	message = strings.TrimSpace(message)
	if message == "" {
		return
	}

	if strings.HasPrefix(message, "/") {
		c.handleCommand(message)
		return
	}

	c.Server.broadcastChat(c.Name, message)
}

func (c *Client) handleCommand(input string) {
	parts := strings.Fields(input)
	if len(parts) == 0 {
		return
	}

	cmd := strings.ToLower(parts[0])

	switch cmd {
	case "/kick":
		if !c.hasRole(RoleMod) {
			c.replyError("permission denied")
			return
		}
		if len(parts) < 2 {
			c.replyError("usage: /kick <userId>")
			return
		}
		c.Server.kick(parts[1], c.Name)
	case "/ban":
		if !c.hasRole(RoleAdmin) {
			c.replyError("permission denied")
			return
		}
		if len(parts) < 2 {
			c.replyError("usage: /ban <userId>")
			return
		}
		c.Server.ban(parts[1], c.Name)
	case "/giveitems":
		if !c.hasRole(RoleAdmin) {
			c.replyError("permission denied")
			return
		}
		if len(parts) < 4 {
			c.replyError("usage: /giveitems <userId> <itemId> <amount>")
			return
		}
		targetID := parts[1]
		itemID := parts[2]
		amount := parts[3]
		c.Server.giveItems(targetID, itemID, amount, c.Name)
	default:
		c.replyError("unknown command")
	}
}

func (c *Client) hasRole(required Role) bool {
	switch c.Role {
	case RoleAdmin:
		return true
	case RoleMod:
		return required == RoleMod || required == RolePlayer
	case RolePlayer:
		return required == RolePlayer
	default:
		return false
	}
}

func (c *Client) replyError(msg string) {
	c.Server.sendTo(c, ServerMessage{
		Type: "error",
		Payload: map[string]string{
			"message": msg,
		},
	})
}

func (s *Server) kick(userID, by string) {
	s.mu.RLock()
	target, ok := s.clients[userID]
	s.mu.RUnlock()

	if !ok {
		return
	}

	s.sendTo(target, ServerMessage{
		Type: "system",
		Payload: map[string]string{
			"message": "You were kicked by " + by,
		},
	})
	_ = target.Conn.Close()
	s.broadcastSystem(target.Name + " was kicked by " + by)
}

func (s *Server) ban(userID, by string) {
	s.mu.Lock()
	s.banned[userID] = true
	target, ok := s.clients[userID]
	s.mu.Unlock()

	if ok {
		s.sendTo(target, ServerMessage{
			Type: "system",
			Payload: map[string]string{
				"message": "You were banned by " + by,
			},
		})
		_ = target.Conn.Close()
		s.broadcastSystem(target.Name + " was banned by " + by)
		return
	}

	s.broadcastSystem(userID + " was banned by " + by)
}

func (s *Server) giveItems(userID, itemID, amount, by string) {
	s.mu.RLock()
	target, ok := s.clients[userID]
	s.mu.RUnlock()

	if !ok {
		return
	}

	s.sendTo(target, ServerMessage{
		Type: "grant_items",
		Payload: map[string]string{
			"itemId": itemID,
			"amount": amount,
			"by":     by,
		},
	})

	s.broadcastSystem(by + " gave items to " + target.Name)
}

